#!/usr/bin/env node
/**
 * RAHE KABA - Payments & Transactions Migration
 * Run: cd server && node migrate-payments.js
 * 
 * This migrates payments and transactions from Supabase.
 * Triggers are DISABLED during import to prevent double-counting,
 * since we're importing the pre-computed transaction ledger directly.
 */

const { Pool } = require('pg');
require('dotenv').config();

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

